const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'TEMPLATES' | 'BLOCKS' | 'DESIGN' | 'FX' | 'ASSETS' | 'JSON'>('TEMPLATES');

  const [dslInput, setDslInput] = useState(INITIAL_DSL);
  const [carousel, setCarousel] = useState<ValidatedCarousel | null>(null);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [zoom, setZoom] = useState(0.40);
  const [toast, setToast] = useState<{ message: string, type: 'success' | 'error' } | null>(null);

  const [activePaletteId, setActivePaletteId] = useState('1');
  const [brandPresets, setBrandPresets] = useState<any[]>(DEFAULT_BRAND_PRESETS);
  const [uploadedBackgrounds, setUploadedBackgrounds] = useState<string[]>([]);
  const [isCreatingPalette, setIsCreatingPalette] = useState(false);
  const [editingPaletteId, setEditingPaletteId] = useState<string | null>(null);
  const [newPaletteData, setNewPaletteData] = useState({
    name: '',
    colors: ['#0D0D0D', '#FFFFFF', '#1fb2f7', '#1fb2f7', '#1fb2f7'],
    font_padrao: 'Inter',
    font_destaque: 'Instrument Serif'
  });

  const [isUploadingFont, setIsUploadingFont] = useState(false);

  const [toolbarState, setToolbarState] = useState<ToolbarState | null>(null);
  const [isDraggingFile, setIsDraggingFile] = useState(false);

  const [showExportModal, setShowExportModal] = useState(false);
  const [selectedSlidesToExport, setSelectedSlidesToExport] = useState<Set<number>>(new Set());

  const [isExporting, setIsExporting] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [exportProgress, setExportProgress] = useState(0);
  const [exportStatus, setExportStatus] = useState('');

  const [templates] = useState<TemplateDefinition[]>(templateRegistry.getAll());

  const currentSlide = useMemo(() => carousel?.slides[currentIndex], [carousel, currentIndex]);
  const imageConfig = useMemo(() => currentSlide?.image, [currentSlide]);

  const [editingIconBlock, setEditingIconBlock] = useState<{ block: Block; index: number } | null>(null);
  const [iconInput, setIconInput] = useState('');

  const canvasRef = useRef<HTMLDivElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);
  const fontInputRef = useRef<HTMLInputElement>(null);
  const bgImageInputRef = useRef<HTMLInputElement>(null);

  const activePalette = useMemo(() => brandPresets.find(p => p.id === activePaletteId), [brandPresets, activePaletteId]);
  const activePaletteColors = useMemo(() => activePalette?.colors || [], [activePalette]);

  const showToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  }, []);

  const updateSlideProperties = useCallback((updates: { path: (string | number)[], value: any }[]) => {
    setDslInput(prev => {
      try {
        const parsed = JSON.parse(prev);
        if (!parsed.slides[currentIndex]) return prev;

        updates.forEach(({ path, value }) => {
          let target = parsed.slides[currentIndex];
          for (let i = 0; i < path.length - 1; i++) {
            const key = path[i];
            if (!target[key] || typeof target[key] !== 'object') target[key] = {};
            target = target[key];
          }
          target[path[path.length - 1]] = value;
        });

        return JSON.stringify(parsed, null, 2);
      } catch (e) {
        return prev;
      }
    });
  }, [currentIndex]);

  const updateGlobalProperty = useCallback((path: (string | number)[], value: any) => {
    setDslInput(prev => {
      try {
        const parsed = JSON.parse(prev);
        let target = parsed;
        for (let i = 0; i < path.length - 1; i++) {
          const key = path[i];
          if (!target[key] || typeof target[key] !== 'object') target[key] = {};
          target = target[key];
        }
        target[path[path.length - 1]] = value;
        return JSON.stringify(parsed, null, 2);
      } catch (e) {
        return prev;
      }
    });
  }, []);

  const updateSlideProperty = useCallback((path: (string | number)[], value: any) => {
    updateSlideProperties([{ path, value }]);
  }, [updateSlideProperties]);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      updateSlideProperty(['image', 'url'], reader.result as string);
    };
    reader.readAsDataURL(file);
  };

  const handleBgImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      const imgUrl = reader.result as string;
      updateSlideProperty(['options', 'backgroundImage'], imgUrl);
      setUploadedBackgrounds(prev => [...new Set([...prev, imgUrl])]);
      showToast("Imagem de fundo aplicada!");
    };
    reader.readAsDataURL(file);
  };

  const handleFontUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const allowedExtensions = ['.ttf', '.otf', '.woff2'];
    const extension = file.name.substring(file.name.lastIndexOf('.')).toLowerCase();
    if (!allowedExtensions.includes(extension)) {
      showToast("Formato não suportado. Use .ttf, .otf ou .woff2", "error");
      return;
    }

    setIsUploadingFont(true);
    try {
      const sanitizedName = file.name.replace(/\s+/g, '_').replace(/[^a-zA-Z0-9._-]/g, '');
      const fileName = `${Date.now()}_${sanitizedName}`;

      const { data, error } = await supabase.storage
        .from('fonts')
        .upload(fileName, file);

      if (error) throw error;

      const { data: { publicUrl } } = supabase.storage
        .from('fonts')
        .getPublicUrl(data.path);

      const fontFamily = sanitizedName.split('.')[0].replace(/[^a-zA-Z0-9]/g, '');
      const newFont: CustomFont = {
        id: crypto.randomUUID(),
        name: file.name.split('.')[0],
        family: fontFamily,
        url: publicUrl
      };

      const nextFonts = [...(carousel?.customFonts || []), newFont];
      updateGlobalProperty(['customFonts'], nextFonts);
      showToast("Fonte sincronizada com sucesso!");
    } catch (err: any) {
      console.error("Font upload error:", err);
      showToast("Erro ao subir para o bucket 'fonts'.", "error");
    } finally {
      setIsUploadingFont(false);
      if (fontInputRef.current) fontInputRef.current.value = '';
    }
  };

  const handleRemoveCustomFont = (fontId: string) => {
    const nextFonts = (carousel?.customFonts || []).filter(f => f.id !== fontId);
    updateGlobalProperty(['customFonts'], nextFonts);
    showToast("Fonte removida da biblioteca.");
  };

  const processProjectFile = useCallback((file: File) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        const parsed = JSON.parse(content);
        const result = carouselSchema.safeParse(parsed);
        if (result.success) {
          setDslInput(content);
          setCurrentIndex(0);
          showToast("Projeto importado com sucesso!");
        } else {
          showToast("Arquivo JSON inválido.", "error");
        }
      } catch (err) {
        showToast("Falha ao ler o arquivo.", "error");
      }
    };
    reader.readAsText(file);
  }, [setDslInput, setCurrentIndex, showToast]);

  const handleImportProject = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) processProjectFile(file);
  };

  const handleGlobalDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(true);
  };

  const handleGlobalDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(false);
  };

  const handleGlobalDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDraggingFile(false);
    const file = e.dataTransfer.files?.[0];
    if (file) processProjectFile(file);
  };

  useEffect(() => {
    const handlePaste = (e: ClipboardEvent) => {
      const items = e.clipboardData?.items;
      if (!items) return;
      for (let i = 0; i < items.length; i++) {
        if (items[i].type.indexOf('image') !== -1) {
          const blob = items[i].getAsFile();
          if (!blob) continue;
          const reader = new FileReader();
          reader.onload = (event) => {
            const result = event.target?.result as string;
            if (result) {
              if (editingIconBlock) {
                updateSlideProperties([
                  { path: ['blocks', editingIconBlock.index, 'options', 'customIcon'], value: result },
                  { path: ['blocks', editingIconBlock.index, 'options', 'icon'], value: undefined }
                ]);
                showToast("Ícone personalizado colado!");
              } else {
                updateSlideProperty(['image', 'url'], result);
                showToast("Imagem do slide atualizada!");
              }
            }
          };
          reader.readAsDataURL(blob);
          e.preventDefault();
          break;
        }
      }
    };
    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, [updateSlideProperty, updateSlideProperties, editingIconBlock, showToast]);

  const loadData = useCallback(async () => {
    setIsSyncing(true);
    try {
      const { data: palettes, error: palError } = await supabase.from('brand_palettes').select('*');
      if (!palError) {
         setBrandPresets([...DEFAULT_BRAND_PRESETS, ...(palettes || [])]);
      }
    } catch (err: any) {
      console.error("Load failed", err);
    } finally {
      setIsSyncing(false);
    }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const handleRender = useCallback(() => {
    try {
      const parsed = JSON.parse(dslInput);
      const result = carouselSchema.safeParse(parsed);
      if (result.success) {
        setCarousel(result.data);
        setError(null);
      } else {
        setError(result.error.issues.map(e => `[${e.path.join(' → ')}]: ${e.message}`).join('\n'));
      }
    } catch (e: any) {
      setError(`Sintaxe: ${e.message}`);
    }
  }, [dslInput]);

  useEffect(() => { handleRender(); }, [handleRender]);

  const handleCanvasMouseUp = (e: React.MouseEvent) => {
    const selection = window.getSelection();
    if (!selection || selection.isCollapsed) return;
    const range = selection.getRangeAt(0);
    const rect = range.getBoundingClientRect();
    const targetBlock = (e.target as HTMLElement).closest('[data-block-index]');
    if (targetBlock) {
       const bIndex = parseInt(targetBlock.getAttribute('data-block-index') || '0', 10);
       const bType = targetBlock.querySelector('[data-block-type]')?.getAttribute('data-block-type') || 'Block';
       const currentBlock = carousel?.slides?.[currentIndex]?.blocks?.[bIndex];
       if (currentBlock) {
          setToolbarState({
            x: Number(rect.left) + Number(rect.width) / 2,
            y: Number(rect.top),
            blockIndex: bIndex,
            blockType: bType,
            options: currentBlock.options || {},
            content: currentBlock.content || ''
          });
       }
    }
  };

  const startBatchExport = async () => {
    if (!carousel || !canvasRef.current || isExporting || selectedSlidesToExport.size === 0) return;
    setShowExportModal(false);
    const originalIndex = currentIndex;
    const exportIndices = Array.from(selectedSlidesToExport).sort((a, b) => Number(a) - Number(b));
    const images: { name: string; dataUrl: string }[] = [];
    setIsExporting(true);
    try {
      const total = exportIndices.length;
      for (let i = 0; i < total; i++) {
        const slideIdx = exportIndices[i];
        setExportStatus(`Renderizando: ${i + 1}/${total}`);
        setExportProgress(Math.round(((i + 1) / total) * 100));
        setCurrentIndex(slideIdx);
        await new Promise(resolve => setTimeout(resolve, 850));
        const dataUrl = await captureJpeg(canvasRef.current);
        images.push({ name: `slide-${(i + 1).toString().padStart(2, '0')}.jpg`, dataUrl });
      }
      setExportStatus('Comprimindo ZIP...');
      await downloadZip(images, `impact-carousel-${Date.now()}.zip`, dslInput);
      setExportStatus('Sucesso!');
      setTimeout(() => {
        setIsExporting(false);
        setExportProgress(0);
        setCurrentIndex(originalIndex);
      }, 1500);
    } catch (err) {
      setError('Erro crítico na exportação.');
      setIsExporting(false);
      setCurrentIndex(originalIndex);
    }
  };

  const handleApplyPalettePreset = (preset: any) => {
    setActivePaletteId(preset.id);
    const defaults = preset.defaults || {
      bg: preset.colors[0],
      accent: preset.colors[2],
      text: preset.colors[1],
      cardBg: preset.colors[2]
    };
    updateSlideProperties([
      { path: ['options', 'background'], value: defaults.bg },
      { path: ['options', 'accent'], value: defaults.accent },
      { path: ['options', 'text'], value: defaults.text },
      { path: ['options', 'cardBg'], value: defaults.cardBg },
      { path: ['options', 'fontPadrão'], value: preset.font_padrao || 'Inter' },
      { path: ['options', 'fontDestaque'], value: preset.font_destaque || 'Instrument Serif' }
    ]);
  };

  const handleCreatePalette = async () => {
    if (!newPaletteData.name.trim()) return;
    setIsSyncing(true);

    const presetData = {
      name: newPaletteData.name,
      colors: newPaletteData.colors,
      font_padrao: newPaletteData.font_padrao,
      font_destaque: newPaletteData.font_destaque,
      defaults: {
        bg: newPaletteData.colors[0],
        accent: newPaletteData.colors[2],
        text: newPaletteData.colors[1],
        cardBg: newPaletteData.colors[2]
      }
    };

    try {
      if (editingPaletteId) {
        const { error: updateError } = await supabase
          .from('brand_palettes')
          .update(presetData)
          .eq('id', editingPaletteId);
        if (updateError) throw updateError;
        showToast("Branding atualizado!");
      } else {
        const { error: insertError } = await supabase
          .from('brand_palettes')
          .insert([{ ...presetData, id: crypto.randomUUID() }]);
        if (insertError) throw insertError;
        showToast("Marca criada!");
      }
    } catch (err: any) {
      console.error("Supabase error", err);
      showToast("Erro ao sincronizar marca.", "error");
    } finally {
      setIsCreatingPalette(false);
      setEditingPaletteId(null);
      setNewPaletteData({ 
        name: '', 
        colors: ['#0D0D0D', '#FFFFFF', '#1fb2f7', '#1fb2f7', '#1fb2f7'],
        font_padrao: 'Inter',
        font_destaque: 'Instrument Serif'
      });
      loadData();
      setIsSyncing(false);
    }
  };

  const handleEditPalette = (e: React.MouseEvent, preset: any) => {
    e.stopPropagation();
    setEditingPaletteId(preset.id);
    setNewPaletteData({
      name: preset.name,
      colors: preset.colors,
      font_padrao: preset.font_padrao || 'Inter',
      font_destaque: preset.font_destaque || 'Instrument Serif'
    });
    setIsCreatingPalette(true);
  };

  const allFontOptions = useMemo(() => {
    const custom = (carousel?.customFonts || []).map(f => ({ id: f.family, label: `${f.name} (Custom)` }));
    return [...GOOGLE_FONTS, ...custom];
  }, [carousel?.customFonts]);

  return (
    <div onDragOver={handleGlobalDragOver} onDragLeave={handleGlobalDragLeave} onDrop={handleGlobalDrop} className="flex h-screen w-full bg-[#050507] text-zinc-300 font-sans overflow-hidden relative">
      {isDraggingFile && (
        <div className="fixed inset-0 z-[10000] bg-brand/10 backdrop-blur-sm border-4 border-dashed border-brand/50 flex items-center justify-center pointer-events-none">
          <div className="bg-zinc-900 p-10 rounded-[40px] shadow-2xl flex flex-col items-center gap-6 animate-in zoom-in-95">
             <Upload size={64} className="text-brand animate-bounce" />
             <p className="text-xl font-black text-white uppercase italic tracking-tighter">Solte o arquivo para importar</p>
          </div>
        </div>
      )}

      {toast && (
        <div className={`fixed bottom-12 left-1/2 -translate-x-1/2 z-[9999] px-12 py-6 rounded-[32px] flex items-center gap-6 animate-in slide-in-from-bottom-12 fade-in duration-500 shadow-[0_30px_90px_rgba(0,0,0,0.6)] backdrop-blur-3xl border border-white/10 ${toast.type === 'success' ? 'bg-brand/95 text-black' : 'bg-red-500/95 text-white'}`}>
          {toast.type === 'success' ? <CheckCircle size={28} strokeWidth={3} /> : <AlertCircle size={28} strokeWidth={3} />}
          <span className="text-[16px] font-black uppercase tracking-[0.1em]">{toast.message}</span>
        </div>
      )}

      <input type="file" ref={importInputRef} onChange={handleImportProject} accept=".json" className="hidden" />
      <input type="file" ref={fontInputRef} onChange={handleFontUpload} accept=".ttf,.otf,.woff2" className="hidden" />
      <input type="file" ref={bgImageInputRef} onChange={handleBgImageUpload} accept="image/*" className="hidden" />

      {toolbarState && (
        <FloatingTextToolbar state={toolbarState} onClose={() => setToolbarState(null)} onUpdate={updateSlideProperties} />
      )}

      {showExportModal && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in" onClick={() => setShowExportModal(false)}>
           <div className="w-full max-w-2xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <div className="space-y-1">
                   <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Exportar Carrossel</h2>
                   <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.2em]">ZIP conterá imagens + JSON do projeto</p>
                 </div>
                 <button onClick={() => setShowExportModal(false)} className="p-3 hover:bg-white/5 rounded-full text-zinc-500 transition-colors"><X size={24}/></button>
              </div>
              <div className="grid grid-cols-4 gap-4 max-h-[400px] overflow-y-auto custom-scrollbar p-1">
                 {carousel?.slides.map((s, idx) => (
                    <button key={idx} onClick={() => { const next = new Set(selectedSlidesToExport); if (next.has(idx)) next.delete(idx); else next.add(idx); setSelectedSlidesToExport(next); }} className={`relative aspect-[4/5] rounded-2xl border-2 transition-all flex flex-col items-center justify-center gap-3 overflow-hidden ${selectedSlidesToExport.has(idx) ? 'border-brand bg-brand/10' : 'border-white/5 bg-black/40 hover:border-white/20'}`}>
                       <div className={`w-10 h-10 rounded-full flex items-center justify-center ${selectedSlidesToExport.has(idx) ? 'bg-brand text-black' : 'bg-zinc-800 text-zinc-500'}`}><span className="font-black text-xs">{idx + 1}</span></div>
                       <p className="text-[10px] font-black uppercase text-zinc-500 tracking-widest truncate px-2 w-full">{s.template.replace(/_/g, ' ')}</p>
                       {selectedSlidesToExport.has(idx) && (<div className="absolute top-2 right-2 text-brand"><CheckCircle2 size={16} /></div>)}
                    </button>
                 ))}
              </div>
              <div className="flex gap-4 pt-4 border-t border-white/5">
                 <button onClick={() => setSelectedSlidesToExport(new Set())} className="px-6 py-5 text-[10px] font-black text-zinc-500 uppercase tracking-widest hover:text-white transition-all">Limpar</button>
                 <button onClick={() => setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i)))} className="px-6 py-5 text-[10px] font-black text-brand uppercase tracking-widest hover:text-brand/80 transition-all">Todos</button>
                 <button onClick={startBatchExport} disabled={selectedSlidesToExport.size === 0} className="flex-1 py-5 bg-brand hover:bg-brand/80 disabled:opacity-30 text-black font-black uppercase rounded-2xl shadow-xl transition-all flex items-center justify-center gap-3"><Download size={18} strokeWidth={3} /> Gerar {selectedSlidesToExport.size} Slides</button>
              </div>
           </div>
        </div>
      )}

      {editingIconBlock && (
        <div className="fixed inset-0 z-[400] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in" onClick={() => setEditingIconBlock(null)}>
           <div className="w-full max-w-2xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <div className="space-y-1">
                   <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">Escolher Ícone</h2>
                   <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.2em]">Biblioteca ou CTRL+V para PNG</p>
                 </div>
                 <button onClick={() => setEditingIconBlock(null)} className="p-3 hover:bg-white/5 rounded-full text-zinc-500"><X size={24}/></button>
              </div>
              <div className="grid grid-cols-4 sm:grid-cols-6 gap-4 p-1">
                 {ICON_LIBRARY_PRESETS.map(item => (
                    <button key={item.id} onClick={() => { updateSlideProperties([{ path: ['blocks', editingIconBlock.index, 'options', 'icon'], value: item.id }, { path: ['blocks', editingIconBlock.index, 'options', 'customIcon'], value: undefined }]); setEditingIconBlock(null); }} className={`flex flex-col items-center justify-center gap-3 p-5 rounded-3xl border-2 transition-all group ${editingIconBlock.block.options?.icon === item.id ? 'border-brand bg-brand/10 text-brand' : 'border-white/5 bg-black/40 hover:border-brand/50'}`}><item.icon size={32} strokeWidth={1.5} className="transition-transform group-hover:scale-110" /><span className="text-[8px] font-black uppercase tracking-tighter text-zinc-600 group-hover:text-brand">{item.label}</span></button>
                 ))}
              </div>
              <div className="space-y-3">
                 <label className="text-[9px] font-black uppercase text-zinc-500 px-1 tracking-widest">Personalizado (URL ou SVG)</label>
                 <div className="flex gap-3"><input type="text" placeholder="https://... ou <svg..." className="flex-1 bg-black/40 border border-white/5 rounded-2xl py-4 px-5 text-sm font-bold text-white outline-none focus:border-brand/50 transition-all" value={iconInput} onChange={(e) => setIconInput(e.target.value)} /><button onClick={() => { updateSlideProperties([{ path: ['blocks', editingIconBlock.index, 'options', 'customIcon'], value: iconInput }, { path: ['blocks', editingIconBlock.index, 'options', 'icon'], value: undefined }]); setEditingIconBlock(null); }} className="px-8 py-4 bg-zinc-800 text-white font-black uppercase text-[10px] rounded-2xl hover:bg-zinc-700 transition-all">Aplicar</button></div>
              </div>
           </div>
        </div>
      )}

      {isCreatingPalette && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-6 bg-black/95 backdrop-blur-2xl animate-in fade-in" onClick={() => { setIsCreatingPalette(false); setEditingPaletteId(null); }}>
           <div className="w-full max-w-xl bg-zinc-900 border border-white/10 rounded-[40px] p-10 space-y-8 shadow-2xl animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex items-center justify-between">
                 <div className="space-y-1">
                   <h2 className="text-xl font-black text-white uppercase italic tracking-tighter">{editingPaletteId ? 'Editar Branding' : 'Novo Branding'}</h2>
                   <p className="text-[10px] font-black uppercase text-zinc-500 tracking-[0.2em]">Cores e Fontes mestras da marca</p>
                 </div>
                 <button onClick={() => { setIsCreatingPalette(false); setEditingPaletteId(null); }} className="p-3 hover:bg-white/5 rounded-full text-zinc-500"><X size={24}/></button>
              </div>
              <div className="space-y-6">
                <input type="text" value={newPaletteData.name} onChange={(e) => setNewPaletteData({ ...newPaletteData, name: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-2xl py-4 px-6 text-base text-white font-bold outline-none focus:border-brand/50 transition-all" placeholder="Nome da Marca" />
                <div className="grid grid-cols-2 gap-4">
                  <select value={newPaletteData.font_padrao} onChange={(e) => setNewPaletteData({ ...newPaletteData, font_padrao: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-xl py-3 px-3 text-[11px] font-bold text-white outline-none">
                    {allFontOptions.map(f => <option key={f.id} value={f.id}>{f.label}</option>)}
                  </select>
                  <select value={newPaletteData.font_destaque} onChange={(e) => setNewPaletteData({ ...newPaletteData, font_destaque: e.target.value })} className="w-full bg-black/40 border border-white/5 rounded-xl py-3 px-3 text-[11px] font-bold text-white outline-none">
                    {allFontOptions.map(f => <option key={f.id} value={f.id}>{f.label}</option>)}
                  </select>
                </div>
                <div className="grid grid-cols-5 gap-4">
                   {['Fundo', 'Texto', 'Accent', 'HL', 'Cards'].map((l, i) => (
                     <div key={i} className="flex flex-col items-center gap-2">
                       <div className="relative w-10 h-10 rounded-full overflow-hidden border border-white/10">
                         <input type="color" value={newPaletteData.colors[i]} onChange={(e) => { const c = [...newPaletteData.colors]; c[i] = e.target.value; setNewPaletteData({ ...newPaletteData, colors: c }); }} className="absolute inset-[-10px] w-[150%] h-[150%] cursor-pointer p-0 m-0 border-none" />
                       </div>
                       <span className="text-[7px] font-black uppercase text-zinc-600">{l}</span>
                     </div>
                   ))}
                </div>
              </div>
              <button onClick={handleCreatePalette} className="w-full py-4 bg-brand text-black font-black uppercase rounded-2xl shadow-2xl transition-all">Sincronizar Branding</button>
           </div>
        </div>
      )}

      {isExporting && (
        <div className="fixed inset-0 z-[500] flex items-center justify-center bg-black/80 backdrop-blur-3xl animate-in fade-in">
           <div className="w-full max-md space-y-10 text-center px-10">
              <div className="relative inline-block"><div className="absolute inset-0 blur-3xl bg-brand/20 animate-pulse rounded-full" /><Loader2 size={64} className="animate-spin text-brand relative mx-auto" strokeWidth={3} /></div>
              <div className="space-y-4"><h2 className="text-2xl font-black text-white uppercase italic tracking-tighter animate-pulse">{exportStatus}</h2><div className="h-2 w-full bg-white/5 rounded-full overflow-hidden"><div className="h-full bg-brand transition-all duration-500" style={{ width: `${exportProgress}%` }} /></div><p className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">{exportProgress}% COMPLETO</p></div>
           </div>
        </div>
      )}

      <div className="flex h-screen w-full">
        <aside className="w-[440px] border-r border-white/5 flex flex-col bg-zinc-900/50 backdrop-blur-2xl z-20 shrink-0">
          <header className="p-5 border-b border-white/5 flex flex-col gap-4">
            <div className="flex items-center justify-between">
              <button onClick={() => importInputRef.current?.click()} className="p-2 bg-white/5 hover:bg-white/10 rounded-lg text-zinc-500 transition-all"><Upload size={18} /></button>
              <img src={LOGO_URL} className="h-8 object-contain" />
              <div className="w-9" />
            </div>
            <nav className="flex gap-1 p-1 bg-black/40 rounded-xl">
              {[
                { id: 'TEMPLATES', icon: Library },
                { id: 'BLOCKS', icon: TypeIcon },
                { id: 'DESIGN', icon: Palette },
                { id: 'FX', icon: Sparkles },
                { id: 'ASSETS', icon: ImageIcon },
                { id: 'JSON', icon: FileJson },
              ].map(tab => (<button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex-1 py-3 rounded-lg flex items-center justify-center transition-all ${activeTab === tab.id ? 'bg-zinc-800 text-brand' : 'text-zinc-500 hover:text-white'}`}><tab.icon size={16} /></button>))}
            </nav>
          </header>
          <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-10">
            {activeTab === 'DESIGN' ? (
              <div className="space-y-10 animate-in slide-in-from-left-4 duration-300">
                <section className="space-y-5">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2.5">
                      <Palette size={16} className="text-brand" />
                      <h3 className="text-[10px] font-black text-zinc-100 uppercase tracking-[0.2em]">Branding do Projeto</h3>
                    </div>
                    <button onClick={() => setIsCreatingPalette(true)} className="p-2 bg-brand/10 text-brand rounded-xl hover:bg-brand/20 transition-all">
                      <Plus size={14} strokeWidth={3} />
                    </button>
                  </div>
                  <div className="grid grid-cols-1 gap-2.5">
                     {brandPresets.map(p => (
                       <button key={p.id} onClick={() => handleApplyPalettePreset(p)} className={`w-full p-4 border rounded-[22px] flex items-center justify-between group transition-all ${activePaletteId === p.id ? 'bg-brand/10 border-brand shadow-lg' : 'bg-white/5 border-white/5 hover:border-white/10'}`}>
                         <div className="flex items-center gap-4">
                           <div className="flex -space-x-1.5">
                             {p.colors.slice(0, 3).map((c: any, i: any) => (
                               <div key={i} className="w-5 h-5 rounded-full border-2 border-zinc-950" style={{ backgroundColor: c }} />
                             ))}
                           </div>
                           <span className={`text-[11px] font-black uppercase tracking-widest ${activePaletteId === p.id ? 'text-brand' : 'text-zinc-500'}`}>{p.name}</span>
                         </div>
                         <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                           {!DEFAULT_BRAND_PRESETS.find(d => d.id === p.id) && <button onClick={(e) => handleEditPalette(e, p)} className="p-1.5 text-zinc-500 hover:text-brand transition-colors"><Pencil size={12}/></button>}
                         </div>
                       </button>
                     ))}
                  </div>
                </section>

                <section className="space-y-8 pt-6 border-t border-white/5">
                  <div className="flex items-center gap-2.5">
                    <Droplet size={16} className="text-brand" />
                    <h3 className="text-[10px] font-black text-zinc-100 uppercase tracking-[0.2em]">Cores Principais</h3>
                  </div>
                  <div className="space-y-6">
                    <div className="space-y-4">
                      <ColorPropertyControl 
                        label="Fundo do Slide" 
                        value={currentSlide?.options?.background || '#0D0D0D'} 
                        paletteColors={activePaletteColors} 
                        onChange={(val) => updateSlideProperty(['options', 'background'], val)} 
                      />

                      {/* BACKGROUND IMAGE UPLOAD IN DESIGN TAB */}
                      <div className="px-1 space-y-2">
                        <div className="flex items-center justify-between">
                           <span className="text-[9px] font-black uppercase text-zinc-500 tracking-widest">Ou usar Imagem</span>
                           {currentSlide?.options?.backgroundImage && (
                             <button onClick={() => updateSlideProperty(['options', 'backgroundImage'], undefined)} className="text-[8px] font-black text-red-500 uppercase hover:text-red-400">Remover</button>
                           )}
                        </div>
                        <button 
                          onClick={() => bgImageInputRef.current?.click()}
                          className={`w-full py-3 rounded-2xl border border-dashed transition-all flex items-center justify-center gap-2 ${currentSlide?.options?.backgroundImage ? 'border-brand/50 bg-brand/5' : 'border-white/10 hover:border-white/20 bg-black/20'}`}
                        >
                          {currentSlide?.options?.backgroundImage ? (
                            <div className="flex items-center gap-2">
                               <ImageIconLucide size={14} className="text-brand" />
                               <span className="text-[10px] font-black uppercase text-brand">Trocar Background</span>
                            </div>
                          ) : (
                            <>
                              <ImagePlus size={14} className="text-zinc-500" />
                              <span className="text-[10px] font-black uppercase text-zinc-500">Subir Imagem Local</span>
                            </>
                          )}
                        </button>
                      </div>
                    </div>

                    <ColorPropertyControl 
                      label="Texto Principal" 
                      value={currentSlide?.options?.text || '#FFFFFF'} 
                      paletteColors={activePaletteColors} 
                      onChange={(val) => updateSlideProperty(['options', 'text'], val)} 
                    />
                    <ColorPropertyControl 
                      label="Cor de Acento" 
                      value={currentSlide?.options?.accent || '#1fb2f7'} 
                      paletteColors={activePaletteColors} 
                      onChange={(val) => updateSlideProperty(['options', 'accent'], val)} 
                    />
                  </div>
                </section>

                <section className="space-y-8 pt-6 border-t border-white/5">
                  <div className="flex items-center gap-2.5">
                    <BoxSelect size={16} className="text-brand" />
                    <h3 className="text-[10px] font-black text-zinc-100 uppercase tracking-[0.2em]">Elementos de Destaque</h3>
                  </div>
                  <div className="grid grid-cols-1 gap-6">
                    <div className="grid grid-cols-1 gap-6">
                        <ColorPropertyControl 
                          label="Fundo Highlight" 
                          value={currentSlide?.options?.hlBgColor || '#1fb2f7'} 
                          paletteColors={activePaletteColors} 
                          onChange={(val) => updateSlideProperty(['options', 'hlBgColor'], val)} 
                        />
                        <ColorPropertyControl 
                          label="Texto Highlight" 
                          value={currentSlide?.options?.hlTextColor || '#000000'} 
                          paletteColors={activePaletteColors} 
                          onChange={(val) => updateSlideProperty(['options', 'hlTextColor'], val)} 
                        />
                    </div>
                    <div className="grid grid-cols-1 gap-6">
                        <ColorPropertyControl 
                          label="Fundo de Card" 
                          value={currentSlide?.options?.cardBg || '#1fb2f7'} 
                          paletteColors={activePaletteColors} 
                          onChange={(val) => updateSlideProperty(['options', 'cardBg'], val)} 
                        />
                        <ColorPropertyControl 
                          label="Texto de Card" 
                          value={currentSlide?.options?.cardTextColor || '#000000'} 
                          paletteColors={activePaletteColors} 
                          onChange={(val) => updateSlideProperty(['options', 'cardTextColor'], val)} 
                        />
                    </div>
                  </div>
                </section>

                <section className="space-y-6 pt-6 border-t border-white/5">
                  <div className="flex items-center gap-2.5"><Baseline size={16} className="text-brand" /><h3 className="text-[10px] font-black text-zinc-100 uppercase tracking-[0.2em]">Tipografia</h3></div>
                  <div className="grid grid-cols-1 gap-5">
                    <div className="space-y-2"><label className="text-[9px] font-black uppercase text-zinc-500 tracking-widest px-1">Fonte Padrão</label><select value={currentSlide?.options?.fontPadrão || 'Inter'} onChange={(e) => updateSlideProperty(['options', 'fontPadrão'], e.target.value)} className="w-full bg-zinc-950/40 border border-white/5 rounded-2xl py-3.5 px-4 text-[11px] font-bold text-white outline-none focus:border-brand/50 transition-all">{allFontOptions.map(f => <option key={f.id} value={f.id}>{f.label}</option>)}</select></div>
                    <div className="space-y-2"><label className="text-[9px] font-black uppercase text-zinc-500 tracking-widest px-1">Fonte Destaque</label><select value={currentSlide?.options?.fontDestaque || 'Instrument Serif'} onChange={(e) => updateSlideProperty(['options', 'fontDestaque'], e.target.value)} className="w-full bg-zinc-950/40 border border-white/5 rounded-2xl py-3.5 px-4 text-[11px] font-bold text-white outline-none focus:border-brand/50 transition-all">{allFontOptions.map(f => <option key={f.id} value={f.id}>{f.label}</option>)}</select></div>
                  </div>
                </section>

                <section className="space-y-6 pt-6 border-t border-white/5 pb-10">
                  <div className="flex items-center gap-2.5"><Frame size={16} className="text-brand" /><h3 className="text-[10px] font-black text-zinc-100 uppercase tracking-[0.2em]">Dimensões</h3></div>
                  <div className="grid grid-cols-1 gap-6">
                    <TransformControl label="Margens" value={currentSlide?.options?.padding ?? 80} min={20} max={200} step={4} onChange={(v) => updateSlideProperty(['options', 'padding'], v)} />
                    <TransformControl label="Espaçamento" value={currentSlide?.options?.blockGap ?? 16} min={0} max={160} step={2} onChange={(v) => updateSlideProperty(['options', 'blockGap'], v)} />
                  </div>
                </section>
              </div>
            ) : activeTab === 'FX' ? (
              <div className="space-y-12 animate-in fade-in slide-in-from-left-4 duration-300">
                <div className="flex items-center gap-2.5">
                  <Sparkles size={18} className="text-brand" />
                  <h3 className="text-[11px] font-black text-zinc-100 uppercase tracking-[0.2em]">Post FX & Textures</h3>
                </div>

                <section className="space-y-10">
                  <TransformControl 
                    label="Intensidade de Luz" 
                    value={currentSlide?.options?.postFX?.lightingIntensity ?? 0} 
                    min={0} max={1} step={0.01} 
                    onChange={(v) => updateSlideProperty(['options', 'postFX', 'lightingIntensity'], v)} 
                    highlight 
                  />
                  <TransformControl 
                    label="Ruído (Grain Amount)" 
                    value={currentSlide?.options?.postFX?.noiseAmount ?? 0} 
                    min={0} max={1} step={0.01} 
                    onChange={(v) => updateSlideProperty(['options', 'postFX', 'noiseAmount'], v)} 
                  />
                  <TransformControl 
                    label="Vinheta (Vignette)" 
                    value={currentSlide?.options?.postFX?.vignette ?? 0} 
                    min={0} max={1} step={0.01} 
                    onChange={(v) => updateSlideProperty(['options', 'postFX', 'vignette'], v)} 
                  />
                  <TransformControl 
                    label="Clareza (Clarity/Contrast)" 
                    value={currentSlide?.options?.postFX?.clarity ?? 0} 
                    min={0} max={1} step={0.01} 
                    onChange={(v) => updateSlideProperty(['options', 'postFX', 'clarity'], v)} 
                  />
                </section>

                <section className="space-y-6 pt-8 border-t border-white/5">
                  <div className="flex items-center gap-2.5"><Wind size={18} className="text-brand" /><h3 className="text-[11px] font-black text-zinc-100 uppercase tracking-[0.2em]">Textura de Papel</h3></div>
                  <div className="space-y-6">
                    <TransformControl 
                      label="Intensidade da Textura" 
                      value={currentSlide?.options?.texture?.amount ?? 0} 
                      min={0} max={1} step={0.01} 
                      onChange={(v) => updateSlideProperty(['options', 'texture', 'amount'], v)} 
                    />
                    <div className="space-y-3">
                      <label className="text-[10px] font-black uppercase text-zinc-500 tracking-widest px-1">Tipo de Textura</label>
                      <select value={currentSlide?.options?.texture?.type || 'none'} onChange={(e) => updateSlideProperty(['options', 'texture', 'type'], e.target.value)} className="w-full bg-black/60 border border-white/5 rounded-2xl py-4 px-4 text-[12px] font-bold text-white outline-none focus:border-brand/50 transition-all">
                        <option value="none">Nenhuma</option>
                        <option value="grain">Grain</option>
                        <option value="paper">Paper</option>
                        <option value="dust">Dust</option>
                      </select>
                    </div>
                  </div>
                </section>
              </div>
            ) : activeTab === 'BLOCKS' ? (
              <div className="space-y-6 animate-in fade-in slide-in-from-left-4 duration-300">
                  {carousel?.slides[currentIndex]?.blocks.map((block, bIdx) => (
                    <div key={bIdx} className="bg-black/40 border border-white/5 rounded-[28px] overflow-hidden group hover:border-white/10 transition-all">
                      <div className="px-6 py-4 bg-black/40 flex items-center justify-between border-b border-white/5">
                        <div className="flex items-center gap-2">
                           <div className="w-1.5 h-1.5 rounded-full bg-brand" />
                           <span className="text-[10px] font-black uppercase text-zinc-400 tracking-widest">{block.type}</span>
                        </div>
                        <button onClick={() => { const next = [...carousel.slides[currentIndex].blocks]; next.splice(bIdx, 1); updateSlideProperty(['blocks'], next); }} className="p-1.5 text-zinc-600 hover:text-red-400 hover:bg-red-400/10 rounded-lg transition-all"><Trash2 size={14} /></button>
                      </div>
                      <div className="p-6 space-y-5">
                         {block.type === 'USER' ? (
                           <div className="space-y-5">
                             <div className="flex gap-4 items-start">
                               <div className="relative w-14 h-14 rounded-full overflow-hidden border border-white/10 shrink-0 group shadow-lg">
                                  <img src={block.options?.avatar || 'https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?auto=format&fit=crop&q=80&w=200'} className="w-full h-full object-cover" />
                                  <input type="file" onChange={(e) => {
                                    const file = e.target.files?.[0];
                                    if (!file) return;
                                    const reader = new FileReader();
                                    reader.onloadend = () => {
                                      updateSlideProperty(['blocks', bIdx, 'options', 'avatar'], reader.result as string);
                                      showToast("Avatar atualizado!");
                                    };
                                    reader.readAsDataURL(file);
                                  }} className="absolute inset-0 opacity-0 cursor-pointer z-10" accept="image/*" />
                                  <div className="absolute inset-0 bg-black/60 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
                                     <Icons.Image size={14} className="text-white" />
                                  </div>
                               </div>
                               <div className="flex-1 space-y-3">
                                  <input 
                                    type="text" 
                                    value={(block.content as string) || ''} 
                                    onChange={(e) => updateSlideProperty(['blocks', bIdx, 'content'], e.target.value)} 
                                    className="w-full bg-black/60 border border-white/5 rounded-xl p-3 text-[12px] font-bold text-white outline-none focus:border-brand/50 transition-all" 
                                    placeholder="Nome do Autor" 
                                  />
                                  <input 
                                    type="text" 
                                    value={block.options?.handle || ''} 
                                    onChange={(e) => updateSlideProperty(['blocks', bIdx, 'options', 'handle'], e.target.value)} 
                                    className="w-full bg-black/60 border border-white/5 rounded-xl p-3 text-[11px] font-bold text-brand outline-none focus:border-brand/50 transition-all" 
                                    placeholder="@handle" 
                                  />
                               </div>
                             </div>
                             <div className="flex items-center justify-between p-3 bg-black/20 rounded-xl border border-white/5">
                                <span className="text-[10px] font-black uppercase text-zinc-500 tracking-widest px-1">Exibir Nome</span>
                                <button 
                                  onClick={() => updateSlideProperty(['blocks', bIdx, 'options', 'hideName'], !block.options?.hideName)}
                                  className={`p-2 rounded-lg transition-all ${!block.options?.hideName ? 'text-brand bg-brand/10' : 'text-zinc-600 bg-white/5'}`}
                                >
                                  {block.options?.hideName ? <EyeOff size={16} /> : <Eye size={16} />}
                                </button>
                             </div>
                             <div className="flex items-center justify-between p-3 bg-black/20 rounded-xl border border-white/5">
                                <span className="text-[10px] font-black uppercase text-zinc-500 tracking-widest px-1">Cor do @</span>
                                <input 
                                  type="color" 
                                  value={block.options?.handleColor || '#1fb2f7'} 
                                  onChange={(e) => updateSlideProperty(['blocks', bIdx, 'options', 'handleColor'], e.target.value)} 
                                  className="w-8 h-8 rounded-lg cursor-pointer bg-transparent border-none p-0 overflow-hidden"
                                />
                             </div>
                           </div>
                         ) : block.type !== 'SPACER' ? (
                           <SafeTextArea 
                             value={(Array.isArray(block.content) ? block.content.join('\n') : block.content as string) || ''} 
                             onChange={(val) => updateSlideProperty(['blocks', bIdx, 'content'], block.type === 'LIST' ? val.split('\n') : val)} 
                             className="w-full bg-black/60 border border-white/5 rounded-2xl p-5 text-[13px] font-medium text-white outline-none focus:border-brand/50 min-h-[120px] custom-scrollbar resize-none transition-all" 
                             placeholder="Digite o conteúdo do slide aqui..." 
                           />
                         ) : null}
                         <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                              <span className="text-[9px] font-black uppercase text-zinc-500 tracking-widest px-1">Tipografia</span>
                              <select value={block.options?.fontVariant || 'padrão'} onChange={(e) => updateSlideProperty(['blocks', bIdx, 'options', 'fontVariant'], e.target.value)} className="w-full bg-black/60 border border-white/5 rounded-xl py-2.5 px-3 text-[10px] font-bold text-white outline-none appearance-none cursor-pointer">
                                <option value="padrão">Padrão</option>
                                <option value="destaque">Destaque</option>
                              </select>
                            </div>
                            <TransformControl label="Size" value={block.options?.fontSize || (block.type === 'USER' ? 32 : 32)} min={10} max={400} step={1} onChange={(v) => updateSlideProperty(['blocks', bIdx, 'options', 'fontSize'], v)} />
                         </div>
                      </div>
                    </div>
                  ))}
                  <button onClick={() => { const n = [...carousel!.slides[currentIndex].blocks, { type: 'PARAGRAPH', content: 'Novo parágrafo...', options: { fontSize: 32 } }]; updateSlideProperty(['blocks'], n); }} className="w-full py-10 border-2 border-dashed border-white/10 rounded-[32px] flex flex-col items-center justify-center gap-3 text-zinc-500 hover:text-brand hover:border-brand/40 hover:bg-brand/5 transition-all active:scale-[0.98]">
                    <PlusCircle size={24}/>
                    <span className="text-[10px] font-black uppercase tracking-[0.2em]">Adicionar Novo Bloco</span>
                  </button>
              </div>
            ) : activeTab === 'ASSETS' ? (
              <div className="space-y-12 animate-in fade-in slide-in-from-left-4 duration-300">
                {/* Main Slide Image Section */}
                <section className="space-y-6">
                  <div className="flex items-center gap-2.5">
                    <ImageIconLucide size={18} className="text-brand" />
                    <h3 className="text-[11px] font-black text-zinc-100 uppercase tracking-[0.2em]">Imagem do Slide</h3>
                  </div>
                  <div className="relative aspect-video rounded-3xl overflow-hidden bg-zinc-950 border border-white/5 group shadow-2xl">
                    {imageConfig?.url ? (
                      <img src={imageConfig.url} className="w-full h-full object-contain" />
                    ) : (
                      <div className="w-full h-full flex flex-col items-center justify-center gap-3 text-zinc-700">
                        <Icons.ImagePlus size={40} />
                        <span className="text-[9px] font-black uppercase tracking-widest">Adicionar Imagem</span>
                      </div>
                    )}
                    <input type="file" onChange={handleImageUpload} className="absolute inset-0 opacity-0 cursor-pointer z-10" accept="image/*" />
                    <div className="absolute inset-0 bg-brand/10 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none border-2 border-dashed border-brand/50 rounded-3xl" />
                  </div>

                  {imageConfig && (
                    <div className="space-y-8 animate-in slide-in-from-top-2">
                       <div className="grid grid-cols-5 gap-2">
                         {IMAGE_TYPE_PRESETS.map(p => (
                           <button 
                             key={p.id} 
                             onClick={() => updateSlideProperty(['image', 'type'], p.id)} 
                             className={`p-3 rounded-xl border flex items-center justify-center transition-all ${imageConfig.type === p.id ? 'bg-brand text-black border-brand shadow-lg scale-105' : 'bg-black/40 border-white/5 text-zinc-500 hover:border-white/20'}`}
                             title={p.label}
                           >
                             <p.icon size={18}/>
                           </button>
                         ))}
                       </div>

                       <div className="grid grid-cols-2 gap-6">
                         <TransformControl label="Posição X" value={imageConfig.boxX || 0} min={-500} max={500} step={1} onChange={(v) => updateSlideProperty(['image', 'boxX'], v)} />
                         <TransformControl label="Posição Y" value={imageConfig.boxY || 0} min={-500} max={500} step={1} onChange={(v) => updateSlideProperty(['image', 'boxY'], v)} />
                       </div>

                       <div className="grid grid-cols-2 gap-6">
                         <TransformControl label="Zoom" value={imageConfig.boxScale || 1} min={0.5} max={3} step={0.05} onChange={(v) => updateSlideProperty(['image', 'boxScale'], v)} />
                         <TransformControl label="Rotação" value={imageConfig.boxRotation || 0} min={-180} max={180} step={1} onChange={(v) => updateSlideProperty(['image', 'boxRotation'], v)} />
                       </div>
                    </div>
                  )}
                </section>

                {/* Custom Backgrounds Section */}
                <section className="space-y-6 pt-8 border-t border-white/5">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2.5">
                      <LayoutTemplate size={18} className="text-brand" />
                      <h3 className="text-[11px] font-black text-zinc-100 uppercase tracking-[0.2em]">Imagem de Fundo</h3>
                    </div>
                    {currentSlide?.options?.backgroundImage && (
                      <button 
                        onClick={() => updateSlideProperty(['options', 'backgroundImage'], undefined)}
                        className="text-[9px] font-black text-red-400 uppercase tracking-widest hover:text-red-300 transition-colors flex items-center gap-1.5"
                      >
                        <Trash2 size={12} /> Remover
                      </button>
                    )}
                  </div>

                  <div 
                    onClick={() => bgImageInputRef.current?.click()}
                    className="relative aspect-[4/5] max-w-[200px] mx-auto rounded-3xl overflow-hidden bg-zinc-950 border border-white/5 group shadow-2xl cursor-pointer hover:border-brand/40 transition-all"
                  >
                    {currentSlide?.options?.backgroundImage ? (
                      <img src={currentSlide.options.backgroundImage} className="w-full h-full object-cover" />
                    ) : (
                      <div className="w-full h-full flex flex-col items-center justify-center gap-3 text-zinc-700">
                        <CloudUpload size={32} />
                        <span className="text-[8px] font-black uppercase tracking-widest">Subir Background</span>
                      </div>
                    )}
                    <div className="absolute inset-0 bg-brand/10 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                       <Plus size={24} className="text-brand" />
                    </div>
                  </div>

                  {uploadedBackgrounds.length > 0 && (
                    <div className="space-y-3">
                      <span className="text-[9px] font-black uppercase text-zinc-500 tracking-widest px-1">Sua Biblioteca</span>
                      <div className="grid grid-cols-4 gap-3">
                         {uploadedBackgrounds.map((bg, idx) => (
                           <button 
                             key={idx} 
                             onClick={() => updateSlideProperty(['options', 'backgroundImage'], bg)}
                             className={`aspect-[4/5] rounded-xl overflow-hidden border-2 transition-all ${currentSlide?.options?.backgroundImage === bg ? 'border-brand scale-105 shadow-lg' : 'border-transparent opacity-60 hover:opacity-100'}`}
                           >
                             <img src={bg} className="w-full h-full object-cover" />
                           </button>
                         ))}
                      </div>
                    </div>
                  )}
                </section>
              </div>
            ) : activeTab === 'TEMPLATES' ? (
              <div className="grid grid-cols-1 gap-2">
                 {templates.map(tpl => (<button key={tpl.name} onClick={() => updateSlideProperty(['template'], tpl.name)} className={`w-full p-4 border rounded-2xl flex items-center gap-4 transition-all ${currentSlide?.template === tpl.name ? 'bg-brand/10 border-brand' : 'bg-white/5 border-white/5 hover:border-white/10'}`}><div className={`w-10 h-10 rounded-xl flex items-center justify-center ${currentSlide?.template === tpl.name ? 'bg-brand text-black' : 'bg-black text-zinc-600'}`}><Library size={18}/></div><div className="text-left"><p className={`text-[10px] font-black uppercase ${currentSlide?.template === tpl.name ? 'text-brand' : 'text-white'}`}>{tpl.name.replace(/_/g, ' ')}</p><p className="text-[8px] text-zinc-600 font-medium truncate max-w-[200px]">{tpl.description}</p></div></button>))}
              </div>
            ) : activeTab === 'JSON' ? (
              <textarea value={dslInput} onChange={(e) => setDslInput(e.target.value)} className="w-full h-[600px] bg-black/40 p-4 font-mono text-[10px] border border-white/5 rounded-2xl outline-none custom-scrollbar" spellCheck={false} />
            ) : null}
          </div>
          <footer className="p-5 border-t border-white/5 bg-zinc-950">
             <button onClick={() => { setSelectedSlidesToExport(new Set(carousel?.slides.map((_, i) => i))); setShowExportModal(true); }} className="w-full py-4 bg-brand text-black font-black rounded-xl text-[10px] uppercase shadow-lg flex items-center justify-center gap-3 active:scale-95"><Download size={16} strokeWidth={3} /> Exportar Tudo</button>
          </footer>
        </aside>
        <main className="flex-1 bg-[#121214] relative flex flex-col">
          {error && <div className="absolute top-5 left-1/2 -translate-x-1/2 z-[100] bg-red-500 text-white px-6 py-3 rounded-2xl flex items-center gap-3 shadow-2xl animate-in slide-in-from-top-4"><AlertCircle size={18}/><span className="text-[11px] font-black uppercase">{error}</span></div>}

          {/* Zoom Controls Left */}
          <div className="absolute left-6 top-1/2 -translate-y-1/2 z-40 flex flex-col items-center gap-4 bg-black/40 backdrop-blur-2xl p-3 rounded-[32px] border border-white/10 shadow-2xl transition-all hover:bg-black/60">
            <button onClick={() => setZoom(Math.min(1.5, zoom + 0.05))} className="p-3 text-zinc-400 hover:text-brand hover:bg-brand/10 rounded-full transition-all active:scale-90" title="Zoom In"><ZoomIn size={20} /></button>
            <div className="w-8 h-[1px] bg-white/10" />
            <div className="text-[10px] font-black font-mono text-zinc-500 py-1 select-none">{(zoom * 100).toFixed(0)}%</div>
            <div className="w-8 h-[1px] bg-white/10" />
            <button onClick={() => setZoom(Math.max(0.1, zoom - 0.05))} className="p-3 text-zinc-400 hover:text-brand hover:bg-brand/10 rounded-full transition-all active:scale-90" title="Zoom Out"><ZoomOut size={20} /></button>
          </div>

          <div className="absolute top-5 right-5 z-40 flex items-center gap-1 bg-black/30 backdrop-blur-xl p-1.5 rounded-xl border border-white/5"><button onClick={() => setZoom(Math.max(0.1, zoom - 0.05))} className="p-1.5 text-zinc-500 hover:text-white"><ZoomOut size={16} /></button><div className="px-2 text-[10px] font-black font-mono text-zinc-400">{(zoom * 100).toFixed(0)}%</div><button onClick={() => setZoom(Math.min(1.5, zoom + 0.05))} className="p-1.5 text-zinc-500 hover:text-white"><ZoomIn size={16} /></button></div>
          <div className="flex-1 flex items-center justify-center overflow-auto p-20" onMouseUp={handleCanvasMouseUp}><div style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }} className="transition-transform duration-500 shadow-[0_60px_150px_rgba(0,0,0,0.8)] shrink-0">{carousel?.slides?.[currentIndex] && <SlideCanvas slide={carousel.slides[currentIndex]} index={currentIndex} canvasRef={canvasRef} onEditIcon={(b, i) => setEditingIconBlock({ block: b, index: i })} customFonts={carousel.customFonts} />}</div></div>
          {carousel && carousel.slides.length > 0 && (<div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-40 flex items-center gap-6 bg-black/50 backdrop-blur-2xl px-8 py-4 rounded-full border border-white/5 shadow-2xl transition-all hover:border-white/10"><button disabled={currentIndex === 0} onClick={() => setCurrentIndex(prev => prev - 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronLeft size={20}/></button><div className="flex gap-2.5">{carousel.slides.map((_, i) => (<button key={i} onClick={() => setCurrentIndex(i)} className={`h-2 transition-all duration-300 rounded-full ${currentIndex === i ? 'w-8 bg-brand' : 'w-2 bg-white/10 hover:bg-white/20'}`} />))}</div><button disabled={currentIndex === carousel.slides.length - 1} onClick={() => setCurrentIndex(prev => prev + 1)} className="p-2 text-zinc-500 hover:text-white disabled:opacity-5 transition-all"><ChevronRight size={20}/></button></div>)}
        </main>
      </div>
    </div>
  );
};

export default App;
